catalog_script_client.script:
function onSubmit() {
    var isValid = true;
    var errorMessages = [];

    // Email validation
    var email = g_form.getValue('email');
    if (!email) {
        errorMessages.push('Email address is required');
        isValid = false;
    }

    // Mobile validation
    var mobile = g_form.getValue('mobile_number');
    if (!mobile) {
        errorMessages.push('Mobile number is required');
        isValid = false;
    }

    // Driving license validation
    var license = g_form.getValue('driving_license');
    if (!license) {
        errorMessages.push('Driving license number is required');
        isValid = false;
    }

    // Vehicle number validation (if auto insurance)
    var policyType = g_form.getValue('policy_type');
    if (policyType === 'auto') {
        var vehicleNumber = g_form.getValue('vehicle_number');
        if (!vehicleNumber) {
            errorMessages.push('Vehicle number is required for auto insurance');
            isValid = false;
        }
    }

    if (!isValid) {
        g_form.addErrorMessage('Please complete all required fields:\n' + errorMessages.join('\n'));
    }

    return isValid;
}
